#include <bits/stdc++.h>
#define zrq0331
#define int long long
using namespace std;
int n;
int Gcd;
int ans;
int b[15];
bool dp[1000005];
signed main() {
	cin >> n;
	for (int i = 1; i <= n; i++) {
		cin >> b[i];
		Gcd = __gcd (Gcd, b[i]);
	}
	if (Gcd != 1) {
		cout << 0;
		return 0;
	}
	dp[0] = 1;
	for (int i = 1; i <= 70000; i++) {
		for (int j = 1; j <= n; j++) {
			if (i >= b[j]) {
				dp[i] |= dp[i - b[j]];
			}
		}
		if (dp[i] == false) {
			ans = i;
		}
	}
	cout << ans;
	return 0;
}
